import boto3  # noqa F401, import as needed for your use case (e.g., sns)
from botocore.exceptions import BotoCoreError   # also need to handle specific exceptions like SNS related errors etc...
# assuming you have already set up AWS credentials in the environment variables or using aws cli and configured boto3 session 
session = boto3.Session(region_name='us-west-2')   
iam = session.client('iam')   # IAM client for handling permissions related operations (e.g., attach role policy)    
roleName = 'sharedLambdaRoleForAllServices'      # name of the new shared iam role 
try:      
    response=iam.create_role(
        RoleName=roleName,   # Name to give your IAM role (e.g., LambdaExecutionRole)    
         AssumeRolePolicyDocument=  {          'Version':'2012-10-17', 
                                            "Statement":[{             
                                                "Action":"sts:AssumeRole",              
                                                 "Principal": {"Service": ["lambda.amazonaws.com"]},                # Service which the role will be assumed (e.g., lambda)  
                                             }]})    
    print("IAM Role created with name ",roleName,response['Role']['Arn']) 
except BotoCoreError as e:      
      error_message = str(e).split('\n')[1].replace(' ', '').replace('{', ':').replace('}', '')   # extract the specific AWS service related exception from boto3 errors     print("BOTOCORE ERROR",error_message)  if there is any error in creating IAM role then it will be printed here.